starterCode.css:
.center-grid {
  display: grid;
  grid-template-columns: 80px 80px;
  grid-template-rows: 80px 80px;
  width: 300px; height: 300px;
  background: #f0f0f0;
  /* Center items in cells */
  /* Center grid in container */
}
.box {
  background: #6c5ce7; color: white;
  padding: 10px; border-radius: 4px;
}

.cards {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 16px;
  /* Default: left-align and top-align items */
}
.card {
  background: #f0f0f0; padding: 20px;
  border-radius: 8px; border: 2px solid transparent;
}
.highlight {
  border-color: #6c5ce7;
  /* Override to center this card */
}
.stick-bottom {
  /* Override to stick to bottom */
}

solution.css:
.cards { display: grid; grid-template-columns: repeat(3, 1fr); gap: 16px; justify-items: start; align-items: start; }
.card { background: #f0f0f0; padding: 20px; border-radius: 8px; border: 2px solid transparent; }
.highlight { border-color: #6c5ce7; place-self: center center; }
.stick-bottom { align-self: end; }

starterCode.css:
.dash {
  display: grid;
  grid-template-columns: 150px 150px 150px;
  grid-template-rows: 1fr 1fr;
  width: 600px; height: 400px;
  background: #1a1a2e;
  /* Center the grid in page: place-content center */
  /* Space-between for tracks */
}

.widget {
  background: #2d2d44; color: #eee;
  padding: 20px; border-radius: 8px;
  display: flex; align-items: center;
