}

solution.css:
.dash { display: grid; grid-template-columns: 150px 150px 150px; grid-template-rows: 1fr 1fr; width: 600px; height: 400px; background: #1a1a2e; place-content: center; justify-content: space-between; }
.widget { background: #2d2d44; color: #eee; padding: 20px; border-radius: 8px; display: flex; align-items: center; justify-content: center; }
.wide { grid-column: span 2; background: #6c5ce7; justify-self: end; align-self: start; }
